pub fn updatewindow(strm: &mut InflateStream, end: &[u8], copy: usize) -> Result<(), InflateError> {
    let wsize = strm.wsize;
    if strm.window.len() < wsize { strm.window.resize(wsize, 0); }
    if copy >= wsize {
        // The new bytes alone fill the whole window — take just the last wsize.
        let src = &end[end.len().saturating_sub(wsize)..];
        strm.window[..wsize].copy_from_slice(src);
        strm.wnext = 0;
        strm.whave = wsize;
    } else {
        let src = &end[end.len().saturating_sub(copy)..];
        let dist = wsize - strm.wnext;
        let first = copy.min(dist);
        strm.window[strm.wnext..strm.wnext + first].copy_from_slice(&src[..first]);
        if copy > first {
            strm.window[..copy - first].copy_from_slice(&src[first..]);
            strm.wnext = copy - first;
        } else {
            strm.wnext += first;
            if strm.wnext == wsize { strm.wnext = 0; }
        }
        strm.whave = (strm.whave + copy).min(wsize);
    }
    Ok(())
}

