pub fn inflate_fixed(strm: &mut InflateStream) -> Result<(), InflateError> {
    // Signal that fixed-table mode is active. Actual codes are embedded in
    // the inflate state machine's code book — a full port would point
    // strm.lencode / strm.distcode at precomputed static tables here.
    strm.mode = 0; // TABLES-ready state placeholder
    Ok(())
}

pub fn inflatePrime(strm: &mut InflateStream, bits: i32, value: i32) -> Result<(), InflateError> {
    if bits < -1 || bits > 16 { return Ok(()); }
    if bits == -1 { strm.hold = 0; strm.bits = 0; return Ok(()); }
    let b = bits as u32;
    let v = (value as u32) & ((1u32 << b) - 1);
    strm.hold |= v << strm.bits;
    strm.bits += b as u8;
    Ok(())
}
